---
import type { HTMLAttributes } from "astro/types"
import type {
  PopoverAlign,
  PopoverSide,
} from "@data-slot/popover"

interface Props extends HTMLAttributes<"div"> {
  defaultOpen?: boolean
  side?: PopoverSide
  align?: PopoverAlign
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
  portal?: boolean
  position?: PopoverPosition
  closeOnClickOutside?: boolean
  closeOnEscape?: boolean
}

/** @deprecated Use `PopoverSide` and the `side` prop instead. */
type PopoverPosition = PopoverSide

const {
  class: className,
  defaultOpen,
  side,
  align,
  sideOffset,
  alignOffset,
  avoidCollisions,
  collisionPadding,
  portal,
  position,
  closeOnClickOutside,
  closeOnEscape,
  ...props
} = Astro.props
---

<div
  data-slot="popover"
  data-default-open={defaultOpen}
  data-side={side}
  data-align={align}
  data-side-offset={sideOffset}
  data-align-offset={alignOffset}
  data-avoid-collisions={avoidCollisions}
  data-collision-padding={collisionPadding}
  data-portal={portal}
  data-position={position}
  data-close-on-click-outside={closeOnClickOutside}
  data-close-on-escape={closeOnEscape}
  class={className}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/popover"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"
import type {
  PopoverAlign,
  PopoverSide,
} from "@data-slot/popover"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"div"> {
  side?: PopoverSide
  align?: PopoverAlign
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
  position?: PopoverPosition
}

/** @deprecated Use `PopoverSide` and the `side` prop instead. */
type PopoverPosition = PopoverSide

const {
  class: className,
  hidden = true,
  side,
  align,
  sideOffset,
  alignOffset,
  avoidCollisions,
  collisionPadding,
  position,
  ...props
} = Astro.props

const booleanDataAttr = (value?: boolean) =>
  value === undefined ? undefined : value ? "" : "false"
---

<div
  data-slot="popover-content"
  data-side={side}
  data-align={align}
  data-side-offset={sideOffset}
  data-align-offset={alignOffset}
  data-avoid-collisions={booleanDataAttr(avoidCollisions)}
  data-collision-padding={collisionPadding}
  data-position={position}
  hidden={hidden}
  class={cn(
    "bg-popover text-popover-foreground ring-foreground/10 z-50 flex w-72 origin-(--transform-origin) flex-col gap-4 rounded-md p-4 text-sm shadow-md ring-1 outline-none duration-100 data-[closed]:animate-out data-[closed]:fade-out-0 data-[closed]:zoom-out-95 data-[open]:animate-in data-[open]:fade-in-0 data-[open]:zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2",
    className
  )}
  {...props}
>
  <slot />
</div>

